def longest_repeat(genome, k):
    if not genome or k <= 0:
        return ""
    n = len(genome)
    if k == 1:
        return genome
    if k > n:
        return ""

    # Build suffix array
    sa = sorted(range(n), key=lambda i: genome[i:])

    # Build LCP array using Kasai's algorithm
    rank = [0] * n
    for i in range(n):
        rank[sa[i]] = i

    lcp = [0] * n
    h = 0
    for i in range(n):
        if rank[i] > 0:
            j = sa[rank[i] - 1]
            while i + h < n and j + h < n and genome[i + h] == genome[j + h]:
                h += 1
            lcp[rank[i]] = h
            if h > 0:
                h -= 1
        else:
            h = 0

    # Sliding window minimum over lcp[1..n-1] with window size k-1
    from collections import deque

    best_len = 0
    best_substr = ""
    window_size = k - 1
    dq = deque()  # indices into lcp, maintaining increasing lcp values

    for i in range(1, n):
        while dq and lcp[dq[-1]] >= lcp[i]:
            dq.pop()
        dq.append(i)

        while dq[0] <= i - window_size:
            dq.popleft()

        if i >= window_size:
            min_lcp = lcp[dq[0]]
            if min_lcp > best_len:
                best_len = min_lcp
                pos = sa[i - window_size]
                best_substr = genome[pos:pos + best_len]
            elif min_lcp == best_len and best_len > 0:
                pos = sa[i - window_size]
                candidate = genome[pos:pos + best_len]
                if candidate < best_substr:
                    best_substr = candidate

    return best_substr

