import unittest

class TestLongestRepeat(unittest.TestCase):

    def test_basic_repeat(self):
        self.assertEqual(longest_repeat("ACGTACGT", 2), "ACGT")

    def test_all_same_k3(self):
        self.assertEqual(longest_repeat("AAAA", 3), "AA")

    def test_no_repeat(self):
        self.assertEqual(longest_repeat("ACGT", 2), "")

    def test_hidden_k_equals_1(self):
        self.assertEqual(longest_repeat("ACGT", 1), "ACGT")

    def test_hidden_single_char_no_repeat(self):
        self.assertEqual(longest_repeat("A", 2), "")

    def test_hidden_longer_overlap(self):
        self.assertEqual(longest_repeat("ACGTACGTAC", 2), "ACGTAC")

    def test_hidden_k_equals_n(self):
        self.assertEqual(longest_repeat("AAA", 3), "A")

    def test_hidden_tiebreak_lex_smallest(self):
        # Both "AC" and "GT" appear twice; lex smallest is "AC"
        self.assertEqual(longest_repeat("ACACGTGT", 2), "AC")

    def test_hidden_alternating_pattern(self):
        # "ATATA" (length 5) appears at positions 0, 2, 4 -> 3 times
        self.assertEqual(longest_repeat("ATATATATA", 3), "ATATA")

    def test_hidden_empty_genome(self):
        self.assertEqual(longest_repeat("", 1), "")

    def test_hidden_k_exceeds_all_occurrences(self):
        # "ACGT"*5 = length 20, each char appears 5 times, k=6 -> nothing qualifies
        self.assertEqual(longest_repeat("ACGT" * 5, 6), "")

    def test_hidden_moderate_periodic(self):
        # "ACGT"*25 = length 100, k=10
        # "ACGT"*m appears (26-m) times. Need 26-m >= 10 -> m <= 16
        # Answer: "ACGT"*16, length 64
        genome = "ACGT" * 25
        result = longest_repeat(genome, 10)
        self.assertEqual(result, "ACGT" * 16)

if __name__ == '__main__':
    unittest.main()
